144.         public async Task<ActionResult> Edit(int? id, string[] selectedCourses)
145.         {
146.             if (id == null)
147.             {
148.                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
149.             }
150.             var instructorToUpdate = db.Instructors
151.                .Include(i => i.OfficeAssignment)
152.                .Include(i => i.CourseAssignments)
153.                    .ThenInclude(c => c.Course)
154.                .Where(i => i.ID == id)
155.                .Single();
156. 
157.             if (await TryUpdateModelAsync<Instructor>(instructorToUpdate, "", i => i.LastName, i => i.FirstMidName, i => i.HireDate, i => i.OfficeAssignment))
158.             {
159.                 try
160.                 {
161.                     if (string.IsNullOrWhiteSpace(instructorToUpdate.OfficeAssignment?.Location))
162.                     {
163.                         instructorToUpdate.OfficeAssignment = null;
164.                     }
165. 
166.                     UpdateInstructorCourses(selectedCourses, instructorToUpdate);
167. 
