using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    [DataRow(10, 1, 5, 2, DisplayName = "10 items, page 1, size 5 => 2 pages")]
    [DataRow(10, 2, 5, 2, DisplayName = "10 items, page 2, size 5 => 2 pages")]
    [DataRow(11, 1, 5, 3, DisplayName = "11 items, page 1, size 5 => 3 pages")]
    [DataRow(1, 1, 5, 1, DisplayName = "1 item, page 1, size 5 => 1 page")]
    [DataRow(0, 1, 5, 0, DisplayName = "0 items, page 1, size 5 => 0 pages")]
    public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageIndex, int pageSize, int expectedTotalPages)
    {
        // Arrange
        var items = new List<int>();

        // Act
        var result = new PaginatedList<int>(items, count, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, result.TotalPages);
    }

    [TestMethod]
    public void Constructor_WithItems_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
        Assert.AreEqual(3, result.Count);
        Assert.AreEqual("a", result[0]);
        Assert.AreEqual("b", result[1]);
        Assert.AreEqual("c", result[2]);
    }

    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange & Act
        var result = new PaginatedList<int>(new List<int>(), 10, 3, 5);

        // Assert
        Assert.AreEqual(3, result.PageIndex);
    }

    [TestMethod]
    [DataRow(1, 5, false, DisplayName = "Page 1 has no previous page")]
    [DataRow(2, 5, true, DisplayName = "Page 2 has previous page")]
    [DataRow(3, 5, true, DisplayName = "Page 3 has previous page")]
    public void HasPreviousPage_VariousPageIndexes_ReturnsExpected(int pageIndex, int totalItems, bool expected)
    {
        // Arrange & Act
        var result = new PaginatedList<int>(new List<int>(), totalItems, pageIndex, 2);

        // Assert
        Assert.AreEqual(expected, result.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 10, 5, true, DisplayName = "Page 1 of 2 has next page")]
    [DataRow(2, 10, 5, false, DisplayName = "Page 2 of 2 has no next page")]
    [DataRow(1, 5, 5, false, DisplayName = "Page 1 of 1 has no next page")]
    [DataRow(1, 15, 5, true, DisplayName = "Page 1 of 3 has next page")]
    public void HasNextPage_VariousPageIndexes_ReturnsExpected(int pageIndex, int count, int pageSize, bool expected)
    {
        // Arrange & Act
        var result = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        // Assert
        Assert.AreEqual(expected, result.HasNextPage);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
        Assert.AreEqual(2, result.PageIndex);
    }

    [TestMethod]
    public void Create_LastPagePartial_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(7, result[1]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any existing notifications from static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_ValidInput_CanBeReceived()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'John Doe' has been created", DisplayName = "CREATE generates correct message")]
    [DataRow(EntityOperation.UPDATE, "Student 'John Doe' has been updated", DisplayName = "UPDATE generates correct message")]
    [DataRow(EntityOperation.DELETE, "Student 'John Doe' has been deleted", DisplayName = "DELETE generates correct message")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "John Doe", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void SendNotification_NoDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", null, EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", "  ", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 42) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", "Math", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_OverloadWithoutDisplayName_Works()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "5", EntityOperation.DELETE, "admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("2", second.EntityId);

        var third = _sut.ReceiveNotification();
        Assert.IsNull(third);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert (no-op for in-memory implementation, but should not throw)
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        _sut.Dispose();
        // Second dispose should also be safe
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = System.DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= System.DateTime.Now.AddSeconds(1));
    }
}

