        _sut.SendNotification("Student", "1", "John Doe", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void SendNotification_NoDisplayName_UsesIdInMessage()
    {
