        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_EmptyDisplayName_UsesIdInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", "  ", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 42) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
