        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("2", second.EntityId);

        var third = _sut.ReceiveNotification();
        Assert.IsNull(third);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert (no-op for in-memory implementation, but should not throw)
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        _sut.Dispose();
        // Second dispose should also be safe
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = System.DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= System.DateTime.Now.AddSeconds(1));
    }
}

