using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests;

/// <summary>
/// Shared helper for creating in-memory SchoolContext instances for testing.
/// </summary>
internal static class TestDbContextFactory
{
    public static SchoolContext Create(string databaseName = null)
    {
        databaseName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName)
            .Options;
        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static SchoolContext CreateWithStudents(string databaseName = null)
    {
        var context = Create(databaseName);
        context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") }
        );
        context.SaveChanges();
        return context;
    }

    public static SchoolContext CreateWithFullData(string databaseName = null)
    {
        var context = Create(databaseName);

        var instructor1 = new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") };
        var instructor2 = new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") };
        context.Instructors.AddRange(instructor1, instructor2);
        context.SaveChanges();

        var dept1 = new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 1 };
        var dept2 = new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 2 };
        context.Departments.AddRange(dept1, dept2);
        context.SaveChanges();

        var course1 = new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 };
        var course2 = new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 };
        context.Courses.AddRange(course1, course2);
        context.SaveChanges();

        context.Students.AddRange(
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") }
        );
        context.SaveChanges();

        context.Enrollments.AddRange(
            new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 1, CourseID = 4022, Grade = Grade.B }
        );
        context.SaveChanges();

        context.CourseAssignments.AddRange(
            new CourseAssignment { CourseID = 1050, InstructorID = 1 },
            new CourseAssignment { CourseID = 4022, InstructorID = 2 }
        );
        context.SaveChanges();

        return context;
    }
}

