namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class ModelValidationTests
{
    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        // Arrange & Act
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        // Assert
        Assert.AreEqual(DateTime.Parse("2023-09-01"), student.EnrollmentDate);
    }

    [TestMethod]
    public void Student_Enrollments_CanBeInitialized()
    {
        // Arrange & Act
        var student = new Student
        {
            Enrollments = new List<Enrollment> { new Enrollment { CourseID = 1 } }
        };

        // Assert
        Assert.AreEqual(1, student.Enrollments.Count);
    }

    [TestMethod]
    public void Course_Properties_CanBeSetAndRead()
    {
        // Arrange & Act
        var course = new Course
        {
            CourseID = 101,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/test.jpg"
        };

        // Assert
        Assert.AreEqual(101, course.CourseID);
        Assert.AreEqual("Test Course", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/images/test.jpg", course.TeachingMaterialImagePath);
    }

    [TestMethod]
    public void Department_Properties_CanBeSetAndRead()
    {
        // Arrange & Act
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Science",
            Budget = 250000m,
            StartDate = DateTime.Parse("2020-01-01"),
            InstructorID = 5,
            RowVersion = new byte[] { 1, 2, 3 }
        };

        // Assert
        Assert.AreEqual(1, dept.DepartmentID);
        Assert.AreEqual("Science", dept.Name);
        Assert.AreEqual(250000m, dept.Budget);
        Assert.AreEqual(DateTime.Parse("2020-01-01"), dept.StartDate);
        Assert.AreEqual(5, dept.InstructorID);
        Assert.AreEqual(3, dept.RowVersion.Length);
    }

    [TestMethod]
    public void Instructor_HireDate_CanBeSet()
    {
        // Arrange & Act
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            HireDate = DateTime.Parse("2000-03-15")
        };

        // Assert
        Assert.AreEqual(DateTime.Parse("2000-03-15"), instructor.HireDate);
    }

    [TestMethod]
    public void Instructor_CourseAssignments_CanBeInitialized()
    {
        // Arrange & Act
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1 },
                new CourseAssignment { CourseID = 2 }
            }
        };

        // Assert
        Assert.AreEqual(2, instructor.CourseAssignments.Count);
    }

    [TestMethod]
    public void Enrollment_Grade_IsNullableAndCanBeNull()
    {
        // Arrange & Act
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 101,
            StudentID = 1,
            Grade = null
        };

        // Assert
