using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private StudentsController _controller;
    private ContosoUniversity.Data.SchoolContext _context;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateWithStudents();
        _controller = new StudentsController(_context);
    }

    private int FirstStudentId => _context.Students.OrderBy(s => s.LastName).First().ID;

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithAllStudents()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByLastName()
    {
        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_FiltersStudentsByFirstName()
    {
        // Act
        var result = _controller.Index(null, null, "Meredith", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_SortByNameDesc_ReturnsSortedStudents()
    {
