        // Act
        var result = _controller.Edit(department) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsNotNull(_controller.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        // Act
        var result = _controller.Delete(FirstDepartmentId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.IsNotNull(model);
        Assert.AreEqual("English", model.Name);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(99999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
    {
        // Arrange
        var initialCount = _context.Departments.Count();

        // Act
        var result = _controller.DeleteConfirmed(FirstDepartmentId) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Departments.Count());
    }
}

