using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private InstructorsController _controller;
    private SchoolContext _context;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateWithFullData();
        _controller = new InstructorsController(_context);
    }

    private int FirstInstructorId => _context.Instructors.OrderBy(i => i.LastName).First().ID;

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithInstructors()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_ReturnsCoursesForInstructor()
    {
        // Arrange
        var instructorId = FirstInstructorId;

        // Act
        var result = _controller.Index(instructorId, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.IsTrue(model.Courses.Any());
    }

    [TestMethod]
    public void Index_WithCourseId_ReturnsEnrollmentsForCourse()
    {
        // Arrange
        var instructorId = FirstInstructorId;

        // Act
        var result = _controller.Index(instructorId, 1050) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Enrollments);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Details(FirstInstructorId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Abercrombie", model.LastName);
        Assert.AreEqual("Kim", model.FirstMidName);
    }

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(99999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2023-01-01")
        };

        // Act
        var result = _controller.Create(instructor, null) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        // Arrange
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2023-01-01")
        };
        var selectedCourses = new[] { "1050" };

        // Act
        var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        var saved = _context.Instructors.First(i => i.LastName == "Instructor");
        Assert.IsTrue(_context.CourseAssignments.Any(ca => ca.InstructorID == saved.ID));
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        // Arrange
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor();

        // Act
        var result = _controller.Create(instructor, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Edit((int?)FirstInstructorId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Act
        var result = _controller.Delete(FirstInstructorId) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual("Abercrombie", model.LastName);
    }

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(99999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        // Arrange
        var initialCount = _context.Instructors.Count();

        // Act
        var result = _controller.DeleteConfirmed(FirstInstructorId) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_InstructorWithDepartment_ClearsDepartmentAdministrator()
    {
        // Arrange - instructor is administrator of a department
        var instructorId = FirstInstructorId;
        var dept = _context.Departments.First(d => d.InstructorID == instructorId);

        // Act
        _controller.DeleteConfirmed(instructorId);

        // Assert
        var updatedDept = _context.Departments.Find(dept.DepartmentID);
        Assert.IsNull(updatedDept.InstructorID);
    }
}

