using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class ModelValidationTests
{
    [TestMethod]
    public void Student_EnrollmentDate_CanBeSet()
    {
        // Arrange & Act
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        // Assert
        Assert.AreEqual(DateTime.Parse("2023-09-01"), student.EnrollmentDate);
    }

    [TestMethod]
    public void Student_Enrollments_CanBeInitialized()
    {
        // Arrange & Act
        var student = new Student
        {
            Enrollments = new List<Enrollment> { new Enrollment { CourseID = 1 } }
        };

        // Assert
        Assert.AreEqual(1, student.Enrollments.Count);
    }

    [TestMethod]
    public void Course_Properties_CanBeSetAndRead()
    {
        // Arrange & Act
        var course = new Course
        {
            CourseID = 101,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/images/test.jpg"
        };

        // Assert
        Assert.AreEqual(101, course.CourseID);
        Assert.AreEqual("Test Course", course.Title);
        Assert.AreEqual(3, course.Credits);
        Assert.AreEqual(1, course.DepartmentID);
        Assert.AreEqual("/images/test.jpg", course.TeachingMaterialImagePath);
    }

    [TestMethod]
    public void Department_Properties_CanBeSetAndRead()
    {
        // Arrange & Act
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Science",
            Budget = 250000m,
            StartDate = DateTime.Parse("2020-01-01"),
            InstructorID = 5,
            RowVersion = new byte[] { 1, 2, 3 }
        };

        // Assert
        Assert.AreEqual(1, dept.DepartmentID);
        Assert.AreEqual("Science", dept.Name);
        Assert.AreEqual(250000m, dept.Budget);
        Assert.AreEqual(DateTime.Parse("2020-01-01"), dept.StartDate);
        Assert.AreEqual(5, dept.InstructorID);
        Assert.AreEqual(3, dept.RowVersion.Length);
    }

    [TestMethod]
    public void Instructor_HireDate_CanBeSet()
    {
        // Arrange & Act
        var instructor = new Instructor
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            HireDate = DateTime.Parse("2000-03-15")
        };

        // Assert
        Assert.AreEqual(DateTime.Parse("2000-03-15"), instructor.HireDate);
    }

    [TestMethod]
    public void Instructor_CourseAssignments_CanBeInitialized()
    {
        // Arrange & Act
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = 1 },
                new CourseAssignment { CourseID = 2 }
            }
        };

        // Assert
        Assert.AreEqual(2, instructor.CourseAssignments.Count);
    }

    [TestMethod]
    public void Enrollment_Grade_IsNullableAndCanBeNull()
    {
        // Arrange & Act
        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 101,
            StudentID = 1,
            Grade = null
        };

        // Assert
        Assert.IsNull(enrollment.Grade);
    }

    [TestMethod]
    [DataRow(Grade.A, DisplayName = "Grade A")]
    [DataRow(Grade.B, DisplayName = "Grade B")]
    [DataRow(Grade.C, DisplayName = "Grade C")]
    [DataRow(Grade.D, DisplayName = "Grade D")]
    [DataRow(Grade.F, DisplayName = "Grade F")]
    public void Enrollment_Grade_AllValuesAssignable(Grade grade)
    {
        // Arrange & Act
        var enrollment = new Enrollment { Grade = grade };

        // Assert
        Assert.AreEqual(grade, enrollment.Grade);
    }

    [TestMethod]
    public void CourseAssignment_Properties_CanBeSetAndRead()
    {
        // Arrange & Act
        var ca = new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 100
        };

        // Assert
        Assert.AreEqual(1, ca.InstructorID);
        Assert.AreEqual(100, ca.CourseID);
    }

    [TestMethod]
    public void OfficeAssignment_Properties_CanBeSetAndRead()
    {
        // Arrange & Act
        var oa = new OfficeAssignment
        {
            InstructorID = 1,
            Location = "Room 101"
        };

        // Assert
        Assert.AreEqual(1, oa.InstructorID);
        Assert.AreEqual("Room 101", oa.Location);
    }

    [TestMethod]
    public void Notification_AllProperties_CanBeSetAndRead()
    {
        // Arrange
        var now = DateTime.UtcNow;

        // Act
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "42",
            Operation = "CREATE",
            Message = "New student created",
            CreatedAt = now,
            CreatedBy = "admin",
            IsRead = false,
            ReadAt = null
        };

        // Assert
        Assert.AreEqual(1, notification.Id);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New student created", notification.Message);
        Assert.AreEqual(now, notification.CreatedAt);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
    }

    [TestMethod]
    public void Notification_ReadAt_CanBeSet()
    {
        // Arrange
        var readTime = DateTime.UtcNow;

        // Act
        var notification = new Notification
        {
            IsRead = true,
            ReadAt = readTime
        };

        // Assert
        Assert.IsTrue(notification.IsRead);
        Assert.AreEqual(readTime, notification.ReadAt);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, DisplayName = "CREATE operation")]
    [DataRow(EntityOperation.UPDATE, DisplayName = "UPDATE operation")]
    [DataRow(EntityOperation.DELETE, DisplayName = "DELETE operation")]
    public void EntityOperation_AllValues_AreValid(EntityOperation operation)
    {
        // Assert - enum values exist and can be used
        Assert.IsTrue(Enum.IsDefined(typeof(EntityOperation), operation));
    }

    [TestMethod]
    public void InstructorIndexData_Properties_CanBeSetAndRead()
    {
        // Arrange & Act
        var viewModel = new InstructorIndexData
        {
            Instructors = new List<Instructor> { new Instructor { LastName = "Test" } },
            Courses = new List<Course> { new Course { Title = "Math" } },
