using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(5, context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(4, context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.IsTrue(context.Enrollments.Count() >= 11);
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(3, context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeededDatabase_DoesNotDuplicate()
    {
        // Arrange
        var context = TestDbContextFactory.Create();
        DbInitializer.Initialize(context);
        var initialStudentCount = context.Students.Count();

        // Act - call Initialize again
        DbInitializer.Initialize(context);

        // Assert - should not add duplicates
        Assert.AreEqual(initialStudentCount, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_SeedData_StudentsHaveValidDates()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        foreach (var student in context.Students)
        {
            Assert.IsTrue(student.EnrollmentDate > System.DateTime.MinValue);
            Assert.IsFalse(string.IsNullOrEmpty(student.FirstMidName));
            Assert.IsFalse(string.IsNullOrEmpty(student.LastName));
        }
    }

    [TestMethod]
    public void Initialize_SeedData_DepartmentsHaveAdministrators()
    {
        // Arrange
        var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        foreach (var dept in context.Departments)
        {
            Assert.IsNotNull(dept.InstructorID);
            Assert.IsTrue(dept.Budget > 0);
            Assert.IsFalse(string.IsNullOrEmpty(dept.Name));
        }
    }
}

